{
  "name": "TitanSchedule Pro",
  "description": "A high-performance enterprise scheduling system with intelligent natural language event creation powered by Gemini, featuring multi-view calendars, task management, and visual productivity analytics."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum EventCategory {
  WORK = 'work',
  PERSONAL = 'personal',
  URGENT = 'urgent',
  MEETING = 'meeting',
  OTHER = 'other'
}

export interface ScheduleEvent {
  id: string;
  title: string;
  start: string; // ISO string
  end: string;   // ISO string
  description?: string;
  category: EventCategory;
  location?: string;
}

export type CalendarView = 'month' | 'week' | 'day';

export interface SmartParseResult {
  title: string;
  start: string;
  end: string;
  category: EventCategory;
  description?: string;
  confidence: number;
}

import { GoogleGenAI, Type } from "@google/genai";
import { SmartParseResult, EventCategory } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

export const parseEventFromText = async (text: string, referenceDate: string): Promise<SmartParseResult | null> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Current reference date and time is ${referenceDate}. 
      Parse the following text into a structured event: "${text}". 
      If no specific time is mentioned, assume it starts at 9:00 AM on the mentioned or current date. 
      Duration should be 1 hour if not specified.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            start: { type: Type.STRING, description: "ISO 8601 formatted date string" },
            end: { type: Type.STRING, description: "ISO 8601 formatted date string" },
            category: { 
              type: Type.STRING, 
              enum: Object.values(EventCategory)
            },
            description: { type: Type.STRING },
            confidence: { type: Type.NUMBER }
          },
          required: ["title", "start", "end", "category", "confidence"]
        }
      }
    });

    const result = JSON.parse(response.text);
    return result as SmartParseResult;
  } catch (error) {
    console.error("Gemini Parsing Error:", error);
    return null;
  }
};

import { 
  format, 
  startOfMonth, 
  endOfMonth, 
  startOfWeek, 
  endOfWeek, 
  eachDayOfInterval, 
  isSameMonth, 
  isSameDay, 
  addMonths, 
  subMonths,
  addDays,
  startOfDay,
  endOfDay,
  isToday,
  parseISO
} from 'date-fns';

export { 
  format, 
  isSameMonth, 
  isSameDay, 
  addMonths, 
  subMonths, 
  addDays,
  isToday,
  parseISO,
  startOfDay,
  endOfDay
};

export const getMonthDays = (date: Date) => {
  const start = startOfWeek(startOfMonth(date));
  const end = endOfWeek(endOfMonth(date));
  return eachDayOfInterval({ start, end });
};

export const getWeekDays = (date: Date) => {
  const start = startOfWeek(date);
  const end = endOfWeek(date);
  return eachDayOfInterval({ start, end });
};

export const getTimeSlots = () => {
  const slots = [];
  for (let i = 0; i < 24; i++) {
    slots.push(`${i.toString().padStart(2, '0')}:00`);
  }
  return slots;
};

