import React, { useState, useEffect } from 'react';
import { ScheduleEvent, EventCategory } from '../types';
import { PlusIcon } from './Icons';
import { format } from '../utils/dateUtils';

interface EventModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (event: Omit<ScheduleEvent, 'id'>) => void;
  initialDate?: Date;
  existingEvent?: ScheduleEvent;
}

const EventModal: React.FC<EventModalProps> = ({ isOpen, onClose, onSave, initialDate, existingEvent }) => {
  const [title, setTitle] = useState('');
  const [startDate, setStartDate] = useState('');
  const [startTime, setStartTime] = useState('09:00');
  const [endDate, setEndDate] = useState('');
  const [endTime, setEndTime] = useState('10:00');
  const [category, setCategory] = useState<EventCategory>(EventCategory.WORK);
  const [description, setDescription] = useState('');

  useEffect(() => {
    if (isOpen) {
      if (existingEvent) {
        const start = new Date(existingEvent.start);
        const end = new Date(existingEvent.end);
        setTitle(existingEvent.title);
        setStartDate(format(start, 'yyyy-MM-dd'));
        setStartTime(format(start, 'HH:mm'));
        setEndDate(format(end, 'yyyy-MM-dd'));
        setEndTime(format(end, 'HH:mm'));
        setCategory(existingEvent.category);
        setDescription(existingEvent.description || '');
      } else if (initialDate) {
        const dateStr = format(initialDate, 'yyyy-MM-dd');
        setStartDate(dateStr);
        setEndDate(dateStr);
        setTitle('');
        setStartTime('09:00');
        setEndTime('10:00');
        setCategory(EventCategory.WORK);
        setDescription('');
      }
    }
  }, [isOpen, initialDate, existingEvent]);

  if (!isOpen) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const start = new Date(`${startDate}T${startTime}:00`).toISOString();
    const end = new Date(`${endDate}T${endTime}:00`).toISOString();
    onSave({
      title,
      start,
      end,
      category,
      description
    });
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black bg-opacity-50 p-4">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md overflow-hidden animate-in fade-in zoom-in duration-200">
        <div className="px-6 py-4 border-b border-gray-100 flex justify-between items-center bg-gray-50">
          <h3 className="text-lg font-semibold text-gray-800">
            {existingEvent ? 'Edit Event' : 'New Schedule Entry'}
          </h3>
          <button onClick={onClose} className="text-gray-400 hover:text-gray-600 transition-colors">
            <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Title</label>
            <input
              type="text"
              required
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all"
              placeholder="Meeting with team..."
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Start Date</label>
              <input
                type="date"
                required
                value={startDate}
                onChange={(e) => setStartDate(e.target.value)}
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Time</label>
              <input
                type="time"
                required
                value={startTime}
                onChange={(e) => setStartTime(e.target.value)}
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
              />
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">End Date</label>
              <input
                type="date"
                required
                value={endDate}
                onChange={(e) => setEndDate(e.target.value)}
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Time</label>
              <input
                type="time"
                required
                value={endTime}
                onChange={(e) => setEndTime(e.target.value)}
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
              />
            </div>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Category</label>
            <select
              value={category}
              onChange={(e) => setCategory(e.target.value as EventCategory)}
              className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
            >
              {Object.values(EventCategory).map(cat => (
                <option key={cat} value={cat}>
                  {cat.charAt(0).toUpperCase() + cat.slice(1)}
                </option>
              ))}
            </select>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Description</label>
            <textarea
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none h-24 resize-none"
              placeholder="Add details..."
            />
          </div>

          <div className="pt-4 flex gap-3">
            <button
              type="button"
              onClick={onClose}
              className="flex-1 px-4 py-2 border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50 transition-colors"
            >
              Cancel
            </button>
            <button
              type="submit"
              className="flex-1 px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-colors font-medium shadow-md shadow-indigo-100"
            >
              {existingEvent ? 'Update' : 'Save Event'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default EventModal;

import React, { useState } from 'react';
import { SparklesIcon } from './Icons';
import { parseEventFromText } from '../services/geminiService';
import { ScheduleEvent } from '../types';

interface SmartInputProps {
  onEventCreated: (event: Omit<ScheduleEvent, 'id'>) => void;
}

const SmartInput: React.FC<SmartInputProps> = ({ onEventCreated }) => {
  const [text, setText] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);

  const handleSuggest = async () => {
    if (!text.trim() || isProcessing) return;

    setIsProcessing(true);
    const now = new Date().toISOString();
    const result = await parseEventFromText(text, now);

    if (result) {
      onEventCreated({
        title: result.title,
        start: result.start,
        end: result.end,
        category: result.category,
        description: result.description || `Auto-parsed from: "${text}"`
      });
      setText('');
    }
    setIsProcessing(false);
  };

  return (
    <div className="relative group">
      <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
        <SparklesIcon className={`w-5 h-5 ${isProcessing ? 'text-indigo-500 animate-pulse' : 'text-gray-400 group-focus-within:text-indigo-500'}`} />
      </div>
      <input
        type="text"
        className="block w-full pl-10 pr-32 py-2.5 border border-gray-200 rounded-xl leading-5 bg-white placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 sm:text-sm transition-all shadow-sm"
        placeholder="Try 'Meeting with Alex at 3pm tomorrow'..."
        value={text}
        onChange={(e) => setText(e.target.value)}
        onKeyDown={(e) => e.key === 'Enter' && handleSuggest()}
      />
      <div className="absolute inset-y-1.5 right-1.5">
        <button
          onClick={handleSuggest}
          disabled={!text.trim() || isProcessing}
          className="inline-flex items-center px-3 py-1 border border-transparent text-xs font-medium rounded-lg shadow-sm text-white bg-indigo-600 hover:bg-indigo-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500 disabled:bg-gray-300 disabled:cursor-not-allowed transition-colors"
        >
          {isProcessing ? 'Thinking...' : 'Add with AI'}
        </button>
      </div>
    </div>
  );
};

export default SmartInput;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  format, 
  getMonthDays, 
  getWeekDays, 
  isSameMonth, 
  isSameDay, 
  addMonths, 
  subMonths, 
  addDays,
  isToday,
  parseISO
} from './utils/dateUtils';
import { ScheduleEvent, CalendarView, EventCategory } from './types';
import { 
  ChevronLeftIcon, 
  ChevronRightIcon, 
  PlusIcon, 
  CalendarIcon, 
  ClockIcon,
  SearchIcon
} from './components/Icons';
import EventModal from './components/EventModal';
import SmartInput from './components/SmartInput';

const App: React.FC = () => {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [view, setView] = useState<CalendarView>('month');
  const [events, setEvents] = useState<ScheduleEvent[]>(() => {
    const saved = localStorage.getItem('titan_events');
    return saved ? JSON.parse(saved) : [];
  });
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedEvent, setSelectedEvent] = useState<ScheduleEvent | undefined>();
  const [searchTerm, setSearchTerm] = useState('');
  const [activeCategory, setActiveCategory] = useState<string | null>(null);

  // Persistence
  useEffect(() => {
    localStorage.setItem('titan_events', JSON.stringify(events));
  }, [events]);

  const filteredEvents = useMemo(() => {
    return events.filter(e => {
      const matchesSearch = e.title.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          e.description?.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesCategory = !activeCategory || e.category === activeCategory;
      return matchesSearch && matchesCategory;
    });
  }, [events, searchTerm, activeCategory]);

  const days = useMemo(() => {
    if (view === 'month') return getMonthDays(currentDate);
    if (view === 'week') return getWeekDays(currentDate);
    return [currentDate];
  }, [currentDate, view]);

  const handlePrev = () => {
    if (view === 'month') setCurrentDate(subMonths(currentDate, 1));
    else if (view === 'week') setCurrentDate(addDays(currentDate, -7));
    else setCurrentDate(addDays(currentDate, -1));
  };

  const handleNext = () => {
    if (view === 'month') setCurrentDate(addMonths(currentDate, 1));
    else if (view === 'week') setCurrentDate(addDays(currentDate, 7));
    else setCurrentDate(addDays(currentDate, 1));
  };

  const addEvent = (eventData: Omit<ScheduleEvent, 'id'>) => {
    const newEvent: ScheduleEvent = {
      ...eventData,
      id: crypto.randomUUID()
    };
    setEvents(prev => [...prev, newEvent]);
  };

  const updateEvent = (eventData: Omit<ScheduleEvent, 'id'>) => {
    if (!selectedEvent) return;
    setEvents(prev => prev.map(e => e.id === selectedEvent.id ? { ...eventData, id: e.id } : e));
    setSelectedEvent(undefined);
  };

  const deleteEvent = (id: string) => {
    if (window.confirm('Delete this event?')) {
      setEvents(prev => prev.filter(e => e.id !== id));
      setSelectedEvent(undefined);
      setIsModalOpen(false);
    }
  };

  const openNewEvent = (date: Date) => {
    setCurrentDate(date);
    setSelectedEvent(undefined);
    setIsModalOpen(true);
  };

  const categoryColors: Record<EventCategory, string> = {
    [EventCategory.WORK]: 'bg-blue-100 text-blue-700 border-blue-200',
    [EventCategory.PERSONAL]: 'bg-green-100 text-green-700 border-green-200',
    [EventCategory.URGENT]: 'bg-rose-100 text-rose-700 border-rose-200',
    [EventCategory.MEETING]: 'bg-amber-100 text-amber-700 border-amber-200',
    [EventCategory.OTHER]: 'bg-slate-100 text-slate-700 border-slate-200',
  };

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      {/* Sidebar */}
      <aside className="w-80 border-r border-slate-200 bg-white p-6 flex flex-col gap-6 overflow-y-auto">
        <div className="flex items-center gap-2 mb-2">
          <div className="bg-indigo-600 p-2 rounded-xl text-white">
            <CalendarIcon className="w-6 h-6" />
          </div>
          <h1 className="text-xl font-bold text-slate-800 tracking-tight">TitanSchedule</h1>
        </div>

        <button 
          onClick={() => { setSelectedEvent(undefined); setIsModalOpen(true); }}
          className="w-full py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-semibold flex items-center justify-center gap-2 transition-all shadow-lg shadow-indigo-100"
        >
          <PlusIcon className="w-5 h-5" />
          Create Event
        </button>

        <div className="space-y-4">
          <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">Quick Add (AI)</label>
          <SmartInput onEventCreated={addEvent} />
        </div>

        <div className="space-y-4">
          <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">Filters</label>
          <div className="relative">
            <SearchIcon className="w-4 h-4 absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
            <input 
              type="text" 
              placeholder="Search events..."
              className="w-full pl-9 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <div className="flex flex-wrap gap-2">
            {Object.values(EventCategory).map(cat => (
              <button 
                key={cat}
                onClick={() => setActiveCategory(activeCategory === cat ? null : cat)}
                className={`px-3 py-1.5 rounded-full text-xs font-medium transition-all border ${
                  activeCategory === cat 
                  ? 'bg-slate-800 text-white border-slate-800' 
                  : 'bg-white text-slate-600 border-slate-200 hover:border-slate-300'
                }`}
              >
                {cat.charAt(0).toUpperCase() + cat.slice(1)}
              </button>
            ))}
          </div>
        </div>

        <div className="mt-auto pt-6 border-t border-slate-100">
          <div className="p-4 bg-indigo-50 rounded-2xl">
            <p className="text-xs font-semibold text-indigo-700 mb-1">Upcoming Meeting</p>
            {events.length > 0 ? (
              <div>
                <p className="text-sm font-bold text-indigo-900 truncate">{events[0].title}</p>
                <p className="text-xs text-indigo-600 opacity-80">{format(new Date(events[0].start), 'MMM dd, h:mm a')}</p>
              </div>
            ) : (
              <p className="text-xs text-indigo-400">No events scheduled.</p>
            )}
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col min-w-0">
        {/* Header */}
        <header className="h-20 bg-white border-b border-slate-200 px-8 flex items-center justify-between shrink-0">
          <div className="flex items-center gap-4">
            <h2 className="text-2xl font-bold text-slate-800 min-w-[200px]">
              {format(currentDate, 'MMMM yyyy')}
            </h2>
            <div className="flex items-center bg-slate-100 rounded-lg p-1">
              <button onClick={handlePrev} className="p-1.5 hover:bg-white hover:shadow-sm rounded-md transition-all">
                <ChevronLeftIcon className="w-5 h-5 text-slate-600" />
              </button>
              <button 
                onClick={() => setCurrentDate(new Date())}
                className="px-3 py-1 text-sm font-medium text-slate-600 hover:text-indigo-600"
              >
                Today
              </button>
              <button onClick={handleNext} className="p-1.5 hover:bg-white hover:shadow-sm rounded-md transition-all">
                <ChevronRightIcon className="w-5 h-5 text-slate-600" />
              </button>
            </div>
          </div>

          <div className="flex items-center gap-3 bg-slate-100 rounded-xl p-1">
            {(['month', 'week', 'day'] as CalendarView[]).map(v => (
              <button
                key={v}
                onClick={() => setView(v)}
                className={`px-4 py-1.5 rounded-lg text-sm font-semibold transition-all ${
                  view === v ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-800'
                }`}
              >
                {v.charAt(0).toUpperCase() + v.slice(1)}
              </button>
            ))}
          </div>
        </header>

        {/* Calendar Grid */}
        <div className="flex-1 overflow-auto p-8">
          <div className="bg-white rounded-2xl shadow-sm border border-slate-200 h-full flex flex-col overflow-hidden">
            {/* Weekdays Header */}
            <div className="calendar-grid border-b border-slate-100 bg-slate-50/50">
              {['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'].map(day => (
                <div key={day} className="py-3 text-center text-xs font-bold text-slate-400 uppercase tracking-widest">
                  {day}
                </div>
              ))}
            </div>

            {/* Grid Body */}
            <div className={`calendar-grid flex-1 ${view === 'month' ? 'auto-rows-fr' : ''}`}>
              {days.map((day, idx) => {
                const dayEvents = filteredEvents.filter(e => isSameDay(new Date(e.start), day));
                const isOutOfMonth = !isSameMonth(day, currentDate);

                return (
                  <div 
                    key={idx}
                    onClick={() => openNewEvent(day)}
                    className={`min-h-[120px] p-2 border-r border-b border-slate-100 relative group transition-colors cursor-pointer
                      ${isOutOfMonth ? 'bg-slate-50/30' : 'bg-white'} 
                      ${idx % 7 === 6 ? 'border-r-0' : ''}
                      hover:bg-indigo-50/30
                    `}
                  >
