      {selectedEvent && (
        <div className="fixed top-0 right-0 w-96 h-screen bg-white shadow-2xl z-40 p-8 border-l border-slate-200 animate-in slide-in-from-right duration-300">
           <div className="flex justify-between items-start mb-8">
              <h3 className="text-xl font-bold text-slate-800">Event Details</h3>
              <button onClick={() => setSelectedEvent(undefined)} className="text-slate-400 hover:text-slate-600">
                <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
           </div>

           <div className="space-y-6">
              <div>
                <label className="text-xs font-bold text-slate-400 uppercase">Title</label>
                <p className="text-lg font-bold text-slate-800">{selectedEvent.title}</p>
              </div>

              <div className="flex gap-4">
                <div className="flex-1">
                  <label className="text-xs font-bold text-slate-400 uppercase">Date</label>
                  <p className="text-sm font-medium text-slate-700">{format(new Date(selectedEvent.start), 'MMMM dd, yyyy')}</p>
                </div>
                <div className="flex-1">
                  <label className="text-xs font-bold text-slate-400 uppercase">Category</label>
                  <p className={`text-xs font-bold inline-block px-2 py-0.5 rounded-full mt-1 ${categoryColors[selectedEvent.category]}`}>
                    {selectedEvent.category}
                  </p>
                </div>
              </div>

              <div>
                <label className="text-xs font-bold text-slate-400 uppercase">Time</label>
                <div className="flex items-center gap-2 text-sm font-medium text-slate-700">
                  <ClockIcon className="w-4 h-4 text-slate-400" />
                  {format(new Date(selectedEvent.start), 'h:mm a')} - {format(new Date(selectedEvent.end), 'h:mm a')}
                </div>
              </div>

              {selectedEvent.description && (
                <div>
                  <label className="text-xs font-bold text-slate-400 uppercase">Description</label>
                  <p className="text-sm text-slate-600 leading-relaxed bg-slate-50 p-4 rounded-xl mt-2">{selectedEvent.description}</p>
                </div>
              )}

              <div className="pt-8 flex gap-3">
                <button 
                  onClick={() => setIsModalOpen(true)}
                  className="flex-1 py-3 bg-slate-100 hover:bg-slate-200 text-slate-700 rounded-xl font-semibold transition-all"
                >
                  Edit
                </button>
                <button 
                  onClick={() => deleteEvent(selectedEvent.id)}
                  className="flex-1 py-3 bg-rose-50 hover:bg-rose-100 text-rose-600 rounded-xl font-semibold transition-all"
                >
                  Delete
                </button>
