};

const App: React.FC = () => {
  const [currentDate, setCurrentDate] = useState(new Date(2025, 10, 1)); // Default to Nov 2025 as per image
  const [shifts, setShifts] = useState<Shift[]>(() => {
    const saved = localStorage.getItem('tech_shifts');
    return saved ? JSON.parse(saved) : [];
  });
  const [aiInput, setAiInput] = useState('');
  const [isProcessingAi, setIsProcessingAi] = useState(false);

  useEffect(() => {
    localStorage.setItem('tech_shifts', JSON.stringify(shifts));
  }, [shifts]);

  const days = useMemo(() => {
    const start = startOfWeek(startOfMonth(currentDate));
    const end = endOfWeek(endOfMonth(currentDate));
    return eachDayOfInterval({ start, end });
  }, [currentDate]);

  const toggleShift = (techId: string, date: string, currentCode?: ShiftCode) => {
    const codes = Object.values(ShiftCode);
    const nextIndex = currentCode ? (codes.indexOf(currentCode) + 1) % (codes.length + 1) : 0;

    setShifts(prev => {
      const filtered = prev.filter(s => !(s.techId === techId && s.date === date));
      if (nextIndex < codes.length) {
        return [...filtered, { techId, date, code: codes[nextIndex] }];
      }
      return filtered;
    });
  };

  const handleAiSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!aiInput.trim() || isProcessingAi) return;

    setIsProcessingAi(true);
    const techNames = INITIAL_TECHNICIANS.map(t => t.name);
    const result = await parseShiftFromText(aiInput, techNames, format(currentDate, 'yyyy-MM-dd'));

    if (result) {
      const tech = INITIAL_TECHNICIANS.find(t => t.name.toLowerCase().includes(result.technicianName.toLowerCase()));
      if (tech) {
        setShifts(prev => {
          const filtered = prev.filter(s => !(s.techId === tech.id && s.date === result.date));
          return [...filtered, { techId: tech.id, date: result.date, code: result.shiftCode }];
        });
        setAiInput('');
      }
    }
    setIsProcessingAi(false);
  };

  const getShift = (techId: string, date: Date) => {
    const dateStr = format(date, 'yyyy-MM-dd');
    return shifts.find(s => s.techId === techId && s.date === dateStr);
  };

  return (
    <div className="flex flex-col h-screen bg-slate-50 text-slate-900 font-sans overflow-hidden">
      {/* Top Banner */}
      <div className="bg-emerald-500 text-white text-[10px] font-bold py-1 px-4 text-center tracking-widest uppercase shrink-0">
        Schedules are subject to change • Internal Technician Management System
      </div>

      {/* Main Header */}
      <header className="bg-white border-b border-slate-200 px-6 py-4 flex items-center justify-between shrink-0">
        <div className="flex items-center gap-6">
          <div className="flex flex-col">
            <h1 className="text-xl font-black text-slate-800 flex items-center gap-2">
              <CalendarIcon className="w-5 h-5 text-indigo-600" />
              {format(currentDate, 'MMMM yyyy')}
            </h1>
            <span className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">Enterprise Resource Planner</span>
          </div>

          <div className="flex items-center bg-slate-100 rounded-lg p-1">
            <button onClick={() => setCurrentDate(subMonths(currentDate, 1))} className="p-1.5 hover:bg-white hover:shadow-sm rounded-md transition-all">
              <ChevronLeftIcon className="w-4 h-4" />
            </button>
            <button onClick={() => setCurrentDate(new Date())} className="px-3 py-1 text-xs font-bold hover:text-indigo-600 transition-colors">Today</button>
            <button onClick={() => setCurrentDate(addMonths(currentDate, 1))} className="p-1.5 hover:bg-white hover:shadow-sm rounded-md transition-all">
              <ChevronRightIcon className="w-4 h-4" />
            </button>
          </div>
        </div>

        <form onSubmit={handleAiSubmit} className="flex-1 max-w-lg mx-8 relative group">
          <SparklesIcon className={`absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 ${isProcessingAi ? 'text-indigo-500 animate-pulse' : 'text-slate-400'}`} />
          <input 
            type="text"
            placeholder="AI Quick Assign: 'Assign Jerry to Vacation on Nov 12'"
            className="w-full bg-slate-100 border-none rounded-xl pl-10 pr-4 py-2 text-sm focus:ring-2 focus:ring-indigo-500 transition-all outline-none"
            value={aiInput}
            onChange={(e) => setAiInput(e.target.value)}
          />
        </form>

        <div className="flex gap-2">
           {Object.entries(SHIFT_METADATA).slice(0, 5).map(([code, meta]) => (
             <div key={code} className="flex items-center gap-1.5 px-2 py-1 bg-white border border-slate-200 rounded-md shadow-sm">
                <div className={`w-2 h-2 rounded-full ${meta.bg}`}></div>
                <span className="text-[10px] font-bold text-slate-500">{code}</span>
             </div>
           ))}
        </div>
      </header>

      {/* Grid Container */}
      <div className="flex-1 overflow-auto p-4 select-none">
        <div className="min-w-max bg-white rounded-xl shadow-xl border border-slate-200 overflow-hidden">
          {/* Calendar Header Row */}
          <div className="flex border-b border-slate-200 sticky top-0 z-20 bg-white">
            <div className="w-64 shrink-0 bg-slate-50 border-r border-slate-200 px-4 py-3 flex items-end">
              <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Technician Information</span>
            </div>
            {days.map((day, idx) => {
              const isStartOfWeek = idx % 7 === 0;
              return (
                <div 
                  key={idx} 
                  className={`w-10 shrink-0 flex flex-col items-center py-2 border-r border-slate-100 
                    ${isStartOfWeek ? 'border-l-2 border-l-slate-300 bg-slate-50/50' : ''}
                    ${!isSameMonth(day, currentDate) ? 'opacity-30' : ''}
                    ${isToday(day) ? 'bg-indigo-50' : ''}
                  `}
                >
                  <span className="text-[9px] font-bold text-slate-400 uppercase">{format(day, 'eeeee')}</span>
                  <span className={`text-xs font-black mt-0.5 ${isToday(day) ? 'text-indigo-600' : 'text-slate-700'}`}>{format(day, 'd')}</span>
                </div>
              );
            })}
          </div>

          {/* Technician Rows */}
          <div className="divide-y divide-slate-100">
            {INITIAL_TECHNICIANS.map((tech) => (
              <div key={tech.id} className="flex hover:bg-slate-50 transition-colors group">
                <div className="w-64 shrink-0 px-4 py-2 border-r border-slate-200 flex items-center justify-between sticky left-0 z-10 bg-inherit shadow-[4px_0_10px_-5px_rgba(0,0,0,0.05)]">
                  <div className="flex flex-col">
                    <span className="text-sm font-bold text-slate-800">{tech.name}</span>
                    <span className="text-[10px] text-slate-400 font-mono tracking-tighter">ID: {tech.id}</span>
                  </div>
                  <span className="text-[10px] font-black text-slate-300 bg-slate-100 px-1.5 py-0.5 rounded uppercase">{tech.code}</span>
                </div>

                {days.map((day, idx) => {
                  const shift = getShift(tech.id, day);
                  const meta = shift ? SHIFT_METADATA[shift.code] : null;
                  const isStartOfWeek = idx % 7 === 0;

                  return (
                    <div
                      key={idx}
                      onClick={() => toggleShift(tech.id, format(day, 'yyyy-MM-dd'), shift?.code)}
                      className={`w-10 h-12 shrink-0 border-r border-slate-100 flex items-center justify-center cursor-pointer transition-all
                        ${isStartOfWeek ? 'border-l-2 border-l-slate-300' : ''}
                        ${!isSameMonth(day, currentDate) ? 'bg-slate-50/20' : ''}
                        hover:scale-[1.05] hover:z-10 hover:shadow-lg
                      `}
                    >
                      {shift ? (
                        <div className={`w-8 h-8 rounded-lg flex items-center justify-center shadow-sm text-[10px] font-black animate-in fade-in zoom-in duration-200 ${meta?.bg} ${meta?.color}`}>
                          {shift.code}
                        </div>
                      ) : (
                        <div className="w-1.5 h-1.5 rounded-full bg-slate-200 group-hover:bg-slate-300 transition-colors"></div>
                      )}
                    </div>
                  );
                })}
              </div>
            ))}
          </div>

          {/* Footer Stats (Mockup matching legacy) */}
          <div className="bg-slate-50 border-t border-slate-200">
            <div className="flex items-center h-8">
              <div className="w-64 px-4 text-[10px] font-bold text-slate-500 uppercase shrink-0 border-r border-slate-200 flex items-center">Total Scheduled</div>
              {days.map((day, idx) => {
                const count = shifts.filter(s => s.date === format(day, 'yyyy-MM-dd')).length;
                return (
                  <div key={idx} className="w-10 text-center text-[10px] font-bold text-slate-700 shrink-0">
                    {count || 0}
                  </div>
                );
              })}
            </div>
            <div className="flex items-center h-8">
              <div className="w-64 px-4 text-[10px] font-bold text-slate-500 uppercase shrink-0 border-r border-slate-200 flex items-center">Not Scheduled</div>
              {days.map((day, idx) => {
                const count = INITIAL_TECHNICIANS.length - shifts.filter(s => s.date === format(day, 'yyyy-MM-dd')).length;
                return (
                  <div key={idx} className="w-10 text-center text-[10px] font-bold text-slate-400 shrink-0">
                    {count}
                  </div>
                );
              })}
            </div>
          </div>
        </div>
      </div>

      {/* Floating Status Key */}
      <div className="fixed bottom-6 right-6 flex gap-2">
        <div className="bg-white px-4 py-3 rounded-2xl shadow-2xl border border-slate-200 flex gap-4">
           <div className="flex flex-col gap-1">
             <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">Status Legends</span>
             <div className="flex gap-3">
                {Object.entries(SHIFT_METADATA).map(([code, meta]) => (
                  <div key={code} className="flex flex-col items-center group relative cursor-help">
                    <div className={`w-8 h-8 rounded-lg flex items-center justify-center text-[10px] font-black ${meta.bg} ${meta.color} shadow-sm`}>
                      {code}
                    </div>
                    <div className="absolute bottom-full mb-2 hidden group-hover:block bg-slate-800 text-white text-[10px] px-2 py-1 rounded whitespace-nowrap z-50">
                      {meta.label}
                    </div>
                  </div>
                ))}
             </div>
           </div>
        </div>
      </div>
    </div>
  );
};

