  endOfWeek
} from 'date-fns';
import { Shift, ShiftCode, Technician } from './types';
import { ChevronLeftIcon, ChevronRightIcon, SparklesIcon, CalendarIcon } from './components/Icons';
import { parseShiftFromText } from './services/geminiService';

const INITIAL_TECHNICIANS: Technician[] = [
  { id: '061', name: 'Jerry Aschoff', code: '061' },
  { id: '261', name: 'Thomas Jimenez', code: '261' },
  { id: '700', name: 'Darrin Westberg', code: '700' },
  { id: '375', name: 'Bryan Baca', code: '375' },
  { id: '170', name: 'Richard Hood', code: '170' },
  { id: '804', name: 'David Winterfeldt', code: '804' },
  { id: '435', name: 'Jeremiah Lawson', code: '435' },
  { id: '391', name: 'Mike Roth Roth', code: '391' },
  { id: '392', name: 'Anthony Paul', code: '392' },
  { id: '429', name: 'Chris Hovelsen', code: '429' },
  { id: '753', name: 'Robert Hernandez', code: '753' },
  { id: '999', name: 'Gavin Erb', code: 'GE' },
];

const SHIFT_METADATA: Record<ShiftCode, { color: string; label: string; bg: string }> = {
  [ShiftCode.OOL]: { color: 'text-white', bg: 'bg-blue-900', label: 'Out of Line' },
  [ShiftCode.BLK]: { color: 'text-slate-500', bg: 'bg-slate-200', label: 'Blackout' },
  [ShiftCode.AIR]: { color: 'text-amber-700', bg: 'bg-amber-100', label: 'Air' },
  [ShiftCode.C]: { color: 'text-emerald-700', bg: 'bg-emerald-100', label: 'C-Shift' },
  [ShiftCode.WRK]: { color: 'text-slate-700', bg: 'bg-slate-100', label: 'Work' },
  [ShiftCode.E]: { color: 'text-slate-700', bg: 'bg-slate-100', label: 'Office' },
  [ShiftCode.NS]: { color: 'text-white', bg: 'bg-rose-600', label: 'No Show' },
  [ShiftCode.V]: { color: 'text-white', bg: 'bg-indigo-600', label: 'Vacation' },
  [ShiftCode.U24]: { color: 'text-blue-600', bg: 'bg-blue-50', label: '24 Unit' },
  [ShiftCode.PDP]: { color: 'text-white', bg: 'bg-purple-600', label: 'PDP Day' },
  [ShiftCode.ENT]: { color: 'text-white', bg: 'bg-teal-600', label: 'Entitlement' },
};

const App: React.FC = () => {
  // Automatically pull up the most recent date (today) when accessed
  const [currentDate, setCurrentDate] = useState(new Date()); 
  const [shifts, setShifts] = useState<Shift[]>(() => {
    const saved = localStorage.getItem('tech_shifts');
    return saved ? JSON.parse(saved) : [];
  });
  const [aiInput, setAiInput] = useState('');
  const [isProcessingAi, setIsProcessingAi] = useState(false);

  // Drag-to-assign state
  const [activeTool, setActiveTool] = useState<ShiftCode | null>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [isLegendMinimized, setIsLegendMinimized] = useState(false);

  useEffect(() => {
    localStorage.setItem('tech_shifts', JSON.stringify(shifts));
  }, [shifts]);

  // Global mouse up to stop dragging
  useEffect(() => {
    const handleMouseUp = () => setIsDragging(false);
    window.addEventListener('mouseup', handleMouseUp);
    return () => window.removeEventListener('mouseup', handleMouseUp);
  }, []);

  const days = useMemo(() => {
    const start = startOfWeek(startOfMonth(currentDate));
    const end = endOfWeek(endOfMonth(currentDate));
    return eachDayOfInterval({ start, end });
  }, [currentDate]);

  const applyShift = useCallback((techId: string, date: string, code: ShiftCode | null) => {
    setShifts(prev => {
      const filtered = prev.filter(s => !(s.techId === techId && s.date === date));
      if (code) {
        return [...filtered, { techId, date, code }];
      }
      return filtered;
    });
  }, []);

  const handleCellAction = (techId: string, date: string, currentCode?: ShiftCode) => {
    if (activeTool) {
      applyShift(techId, date, activeTool === currentCode ? null : activeTool);
    } else {
      const codes = Object.values(ShiftCode);
      const nextIndex = currentCode ? (codes.indexOf(currentCode) + 1) % (codes.length + 1) : 0;
      if (nextIndex < codes.length) {
        applyShift(techId, date, codes[nextIndex]);
      } else {
        applyShift(techId, date, null);
      }
    }
  };

  const handleAiSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!aiInput.trim() || isProcessingAi) return;

    setIsProcessingAi(true);
    const techNames = INITIAL_TECHNICIANS.map(t => t.name);
    const result = await parseShiftFromText(aiInput, techNames, format(currentDate, 'yyyy-MM-dd'));

    if (result) {
      const tech = INITIAL_TECHNICIANS.find(t => t.name.toLowerCase().includes(result.technicianName.toLowerCase()));
      if (tech) {
        applyShift(tech.id, result.date, result.shiftCode);
        setAiInput('');
      }
    }
    setIsProcessingAi(false);
  };

  const getShift = (techId: string, date: Date) => {
    const dateStr = format(date, 'yyyy-MM-dd');
    return shifts.find(s => s.techId === techId && s.date === dateStr);
  };

  return (
    <div className={`flex flex-col h-screen bg-slate-50 text-slate-900 font-sans overflow-hidden ${activeTool ? 'cursor-crosshair' : ''}`}>
      <div className="bg-emerald-500 text-white text-[10px] font-bold py-1 px-4 text-center tracking-widest uppercase shrink-0">
        Schedules are subject to change • Drag to Assign Enabled {activeTool ? `(Active: ${activeTool})` : ''}
      </div>

      <header className="bg-white border-b border-slate-200 px-6 py-4 flex items-center justify-between shrink-0">
        <div className="flex items-center gap-6">
          <div className="flex flex-col">
            <h1 className="text-xl font-black text-slate-800 flex items-center gap-2">
              <CalendarIcon className="w-5 h-5 text-indigo-600" />
              {format(currentDate, 'MMMM yyyy')}
            </h1>
            <span className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">Enterprise Resource Planner</span>
          </div>

          <div className="flex items-center bg-slate-100 rounded-lg p-1">
            <button onClick={() => setCurrentDate(subMonths(currentDate, 1))} className="p-1.5 hover:bg-white hover:shadow-sm rounded-md transition-all">
              <ChevronLeftIcon className="w-4 h-4" />
            </button>
            <button onClick={() => setCurrentDate(new Date())} className="px-3 py-1 text-xs font-bold hover:text-indigo-600 transition-colors text-slate-600">Today</button>
            <button onClick={() => setCurrentDate(addMonths(currentDate, 1))} className="p-1.5 hover:bg-white hover:shadow-sm rounded-md transition-all">
              <ChevronRightIcon className="w-4 h-4" />
            </button>
          </div>
        </div>

        <form onSubmit={handleAiSubmit} className="flex-1 max-w-lg mx-8 relative group">
          <SparklesIcon className={`absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 ${isProcessingAi ? 'text-indigo-500 animate-pulse' : 'text-slate-400'}`} />
          <input 
            type="text"
            placeholder="AI Quick Assign: 'Mark Jerry as ENT for tomorrow'"
            className="w-full bg-slate-100 border-none rounded-xl pl-10 pr-4 py-2 text-sm focus:ring-2 focus:ring-indigo-500 transition-all outline-none"
            value={aiInput}
            onChange={(e) => setAiInput(e.target.value)}
          />
        </form>

        <div className="flex gap-2">
           {Object.entries(SHIFT_METADATA).slice(0, 6).map(([code, meta]) => (
             <button 
                key={code} 
                onClick={() => setActiveTool(activeTool === code ? null : code as ShiftCode)}
                className={`flex items-center gap-1.5 px-2 py-1 border rounded-md transition-all shadow-sm ${activeTool === code ? 'ring-2 ring-indigo-500 border-indigo-500 bg-indigo-50' : 'bg-white border-slate-200'}`}
              >
                <div className={`w-2 h-2 rounded-full ${meta.bg}`}></div>
                <span className="text-[10px] font-bold text-slate-500">{code}</span>
             </button>
           ))}
        </div>
      </header>

      <div className="flex-1 overflow-auto p-4 select-none">
        <div className="min-w-max bg-white rounded-xl shadow-xl border border-slate-200 overflow-hidden">
          <div className="flex border-b border-slate-200 sticky top-0 z-20 bg-white">
            <div className="w-64 shrink-0 bg-slate-50 border-r border-slate-200 px-4 py-3 flex items-end">
              <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Technician Information</span>
            </div>
            {days.map((day, idx) => {
              const isStartOfWeek = idx % 7 === 0;
              return (
                <div 
                  key={idx} 
                  className={`w-10 shrink-0 flex flex-col items-center py-2 border-r border-slate-100 
                    ${isStartOfWeek ? 'border-l-2 border-l-slate-300 bg-slate-50/50' : ''}
                    ${!isSameMonth(day, currentDate) ? 'opacity-30' : ''}
                    ${isToday(day) ? 'bg-indigo-50' : ''}
                  `}
                >
                  <span className="text-[9px] font-bold text-slate-400 uppercase">{format(day, 'eeeee')}</span>
                  <span className={`text-xs font-black mt-0.5 ${isToday(day) ? 'text-indigo-600' : 'text-slate-700'}`}>{format(day, 'd')}</span>
                </div>
              );
            })}
          </div>

          <div className="divide-y divide-slate-100">
            {INITIAL_TECHNICIANS.map((tech) => (
              <div key={tech.id} className="flex hover:bg-slate-50 transition-colors group">
                <div className="w-64 shrink-0 px-4 py-2 border-r border-slate-200 flex items-center justify-between sticky left-0 z-10 bg-inherit shadow-[4px_0_10px_-5px_rgba(0,0,0,0.05)]">
                  <div className="flex flex-col">
                    <span className="text-sm font-bold text-slate-800">{tech.name}</span>
                    <span className="text-[10px] text-slate-400 font-mono tracking-tighter">ID: {tech.id}</span>
                  </div>
                  <span className="text-[10px] font-black text-slate-300 bg-slate-100 px-1.5 py-0.5 rounded uppercase">{tech.code}</span>
                </div>

                {days.map((day, idx) => {
                  const shift = getShift(tech.id, day);
                  const meta = shift ? SHIFT_METADATA[shift.code] : null;
                  const isStartOfWeek = idx % 7 === 0;
                  const dateStr = format(day, 'yyyy-MM-dd');

                  return (
                    <div
                      key={idx}
                      onMouseDown={() => {
                        handleCellAction(tech.id, dateStr, shift?.code);
                        setIsDragging(true);
                      }}
                      onMouseEnter={() => {
                        if (isDragging && activeTool) {
                          applyShift(tech.id, dateStr, activeTool);
                        }
                      }}
                      className={`w-10 h-12 shrink-0 border-r border-slate-100 flex items-center justify-center cursor-pointer transition-all
                        ${isStartOfWeek ? 'border-l-2 border-l-slate-300' : ''}
                        ${!isSameMonth(day, currentDate) ? 'bg-slate-50/20' : ''}
                        ${activeTool && !shift ? 'hover:bg-indigo-50/50' : ''}
                      `}
                    >
                      {shift ? (
                        <div className={`w-8 h-8 rounded-lg flex items-center justify-center shadow-sm text-[10px] font-black animate-in fade-in zoom-in duration-200 ${meta?.bg} ${meta?.color}`}>
                          {shift.code}
                        </div>
                      ) : (
                        <div className="w-1 h-1 rounded-full bg-slate-200 group-hover:bg-slate-300 transition-colors"></div>
                      )}
                    </div>
                  );
                })}
              </div>
            ))}
          </div>

          <div className="bg-slate-50 border-t border-slate-200">
            <div className="flex items-center h-8">
              <div className="w-64 px-4 text-[10px] font-bold text-slate-500 uppercase shrink-0 border-r border-slate-200 flex items-center">Total Scheduled</div>
              {days.map((day, idx) => {
                const count = shifts.filter(s => s.date === format(day, 'yyyy-MM-dd')).length;
                return (
                  <div key={idx} className="w-10 text-center text-[10px] font-bold text-slate-700 shrink-0">
                    {count || 0}
                  </div>
                );
              })}
            </div>
          </div>
        </div>
      </div>

      <div className="fixed bottom-6 right-6 flex flex-col items-end gap-3 pointer-events-none">
        {activeTool && (
          <div className="bg-indigo-600 text-white px-4 py-2 rounded-full shadow-2xl text-xs font-bold animate-in slide-in-from-bottom duration-300 pointer-events-auto flex items-center">
            <SparklesIcon className="w-3.5 h-3.5 mr-2" />
            Painting Mode: {SHIFT_METADATA[activeTool].label}
            <button 
              onClick={() => setActiveTool(null)}
              className="ml-3 bg-white/20 hover:bg-white/40 px-2 py-0.5 rounded-md text-[10px]"
            >
              Cancel
            </button>
          </div>
        )}

        <div className="pointer-events-auto">
          {isLegendMinimized ? (
            <button
              onClick={() => setIsLegendMinimized(false)}
              className="bg-white p-3 rounded-full shadow-2xl border border-slate-200 hover:bg-indigo-50 transition-all flex items-center gap-2 group animate-in zoom-in duration-200"
            >
              <CalendarIcon className="w-5 h-5 text-indigo-600" />
              <span className="text-[10px] font-black text-slate-600 uppercase tracking-widest hidden group-hover:inline">Shift Legend</span>
            </button>
          ) : (
            <div className="bg-white p-4 rounded-2xl shadow-2xl border border-slate-200 animate-in slide-in-from-right duration-300 relative min-w-[320px]">
              <div className="flex justify-between items-center mb-3">
                <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Status Legend (Click to pick tool)</span>
                <button 
                  onClick={() => setIsLegendMinimized(true)}
                  className="p-1 hover:bg-slate-100 rounded-md text-slate-400 hover:text-slate-600 transition-colors"
                >
                  <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
                  </svg>
                </button>
              </div>

              <div className="grid grid-cols-4 sm:grid-cols-6 gap-2">
                {(Object.keys(SHIFT_METADATA) as Array<keyof typeof SHIFT_METADATA>).map((code) => {
                  const meta = SHIFT_METADATA[code];
                  const isActive = activeTool === code;
                  return (
                    <button
                      key={code}
                      onClick={() => setActiveTool(isActive ? null : code)}
                      title={meta.label}
                      className={`
                        flex flex-col items-center p-2 rounded-xl transition-all border
                        ${isActive ? 'ring-2 ring-indigo-500 border-indigo-500 bg-indigo-50 scale-105 z-10' : 'bg-white border-slate-100 hover:border-slate-300 hover:bg-slate-50'}
                      `}
                    >
                      <div className={`w-8 h-8 rounded-lg flex items-center justify-center text-[10px] font-black shadow-sm ${meta.bg} ${meta.color}`}>
                        {code}
                      </div>
                      <span className="text-[8px] mt-1 font-bold text-slate-500 overflow-hidden text-ellipsis whitespace-nowrap w-8 text-center">{code}</span>
                    </button>
                  );
                })}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

