const App: React.FC = () => {
  const [currentDate, setCurrentDate] = useState(new Date()); 
  const [shifts, setShifts] = useState<Shift[]>(() => {
    const saved = localStorage.getItem('tech_shifts');
    return saved ? JSON.parse(saved) : [];
  });
  const [aiInput, setAiInput] = useState('');
  const [isProcessingAi, setIsProcessingAi] = useState(false);

  const [activeTool, setActiveTool] = useState<ShiftCode | null>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [isLegendMinimized, setIsLegendMinimized] = useState(false);

  useEffect(() => {
    localStorage.setItem('tech_shifts', JSON.stringify(shifts));
  }, [shifts]);

  useEffect(() => {
    const handleMouseUp = () => setIsDragging(false);
    window.addEventListener('mouseup', handleMouseUp);
    return () => window.removeEventListener('mouseup', handleMouseUp);
  }, []);

  const days = useMemo(() => {
    const start = startOfWeek(startOfMonth(currentDate));
    const end = endOfWeek(endOfMonth(currentDate));
    return eachDayOfInterval({ start, end });
  }, [currentDate]);

  const applyShift = useCallback((techId: string, date: string, code: ShiftCode | null) => {
    setShifts(prev => {
      const filtered = prev.filter(s => !(s.techId === techId && s.date === date));
      if (code) {
        return [...filtered, { techId, date, code }];
      }
      return filtered;
    });
  }, []);

  const apply2026Vacations = () => {
    const confirmV = window.confirm("This will overwrite existing shifts on specific vacation dates in 2026. Proceed?");
    if (!confirmV) return;

    // Helper to generate date strings for ranges
    const range = (start: string, end: string) => {
      return eachDayOfInterval({ start: new Date(start), end: new Date(end) }).map(d => format(d, 'yyyy-MM-dd'));
    };

    const vacationData: Record<string, string[]> = {
      '700': ['2026-01-02', '2026-04-23', '2026-04-24', ...range('2026-07-06', '2026-07-10'), ...range('2026-11-23', '2026-11-27'), ...range('2026-12-07', '2026-12-11'), ...range('2026-12-14', '2026-12-18'), ...range('2026-12-28', '2026-12-31')], // Darrin Westberg
      '392': ['2026-01-02', ...range('2026-03-23', '2026-03-27'), ...range('2026-06-01', '2026-06-05'), ...range('2026-12-28', '2026-12-31')], // Anthony/Tony Paul
      '804': ['2026-01-02', '2026-01-23', '2026-01-30', '2026-02-13', '2026-02-20', '2026-03-13', ...range('2026-03-16', '2026-03-20'), '2026-04-10', '2026-04-17', '2026-04-24', '2026-07-31', '2026-09-18', ...range('2026-09-21', '2026-09-30'), '2026-10-01', '2026-10-02', ...range('2026-12-21', '2026-12-24')], // David Winterfeldt
      '170': ['2026-01-05', ...range('2026-01-20', '2026-01-23'), ...range('2026-03-23', '2026-03-27')], // Richard Hood
      '375': [...range('2026-01-05', '2026-01-09'), ...range('2026-01-12', '2026-01-16'), ...range('2026-05-18', '2026-05-22')], // Bryan Baca
      '261': ['2026-01-16', '2026-03-16', '2026-04-17', '2026-04-20', '2026-05-22', ...range('2026-05-26', '2026-05-29'), ...range('2026-06-22', '2026-06-23'), ...range('2026-07-06', '2026-07-10'), ...range('2026-09-04', '2026-09-11'), ...range('2026-11-23', '2026-11-27')], // Thomas/Tom Jimenez
      '171': [...range('2026-01-26', '2026-01-27'), '2026-03-20', '2026-03-30', '2026-04-10', '2026-04-14', '2026-05-14', '2026-05-15', '2026-05-18'], // Jason Hood
      '391': [...range('2026-02-02', '2026-02-06'), ...range('2026-02-09', '2026-02-13'), ...range('2026-06-22', '2026-06-23'), ...range('2026-06-24', '2026-06-26'), ...range('2026-06-29', '2026-07-03')], // Michael/Mike Roth
      '753': [...range('2026-02-16', '2026-02-20')], // Robert Hernandez
      '061': [ ...range('2026-05-26', '2026-05-29'), '2026-06-05', ...range('2026-06-08', '2026-06-12'), '2026-07-03', '2026-07-17', ...range('2026-07-20', '2026-07-24'), '2026-08-07', '2026-08-14', '2026-09-04', ...range('2026-09-08', '2026-09-11')], // Jerry Aschoff
      '429': [...range('2026-06-15', '2026-06-19'), ...range('2026-07-20', '2026-07-24'), ...range('2026-11-02', '2026-11-06')], // Chris Hovelsen/Holverson
      '435': [...range('2026-07-13', '2026-07-17'), ...range('2026-07-27', '2026-07-31'), ...range('2026-12-21', '2026-12-24')] // Jeremiah Lawson
    };

    setShifts(prev => {
      let nextShifts = [...prev];
      Object.entries(vacationData).forEach(([techId, dates]) => {
        dates.forEach(date => {
          nextShifts = nextShifts.filter(s => !(s.techId === techId && s.date === date));
          nextShifts.push({ techId, date, code: ShiftCode.V });
        });
      });
      return nextShifts;
    });
    alert("2026 Vacations applied successfully!");
  };

  const fillMonthForTech = (techId: string) => {
    if (!activeTool) {
      alert("Please select a status from the legend first to use as a fill tool.");
      return;
    }
    const start = startOfMonth(currentDate);
    const end = endOfMonth(currentDate);
    const monthDays = eachDayOfInterval({ start, end });
    setShifts(prev => {
      const otherShifts = prev.filter(s => {
        const isThisTech = s.techId === techId;
        const isThisMonth = isSameMonth(new Date(s.date), currentDate);
        return !(isThisTech && isThisMonth);
      });
      const newMonthShifts = monthDays.map(day => ({
        techId,
        date: format(day, 'yyyy-MM-dd'),
        code: activeTool
      }));
      return [...otherShifts, ...newMonthShifts];
    });
  };

  const populateWrkThrough2026 = () => {
    const confirmPopulate = window.confirm("This will fill all empty dates from today through December 31, 2026 with the 'WRK' status for all technicians. Proceed?");
    if (!confirmPopulate) return;
    const startDate = new Date();
    const endDate = new Date(2026, 11, 31);
    const allDays = eachDayOfInterval({ start: startDate, end: endDate });
    setShifts(prev => {
      const shiftMap = new Map();
      prev.forEach(s => shiftMap.set(`${s.techId}_${s.date}`, s));
      const newShifts = [...prev];
      INITIAL_TECHNICIANS.forEach(tech => {
        allDays.forEach(day => {
          const dateStr = format(day, 'yyyy-MM-dd');
          const key = `${tech.id}_${dateStr}`;
          if (!shiftMap.has(key)) {
            newShifts.push({ techId: tech.id, date: dateStr, code: ShiftCode.WRK });
          }
        });
      });
      return newShifts;
    });
    alert("Schedule populated with WRK status through 2026!");
  };

  const handleCellAction = (techId: string, date: string, currentCode?: ShiftCode) => {
    if (activeTool) {
      applyShift(techId, date, activeTool === currentCode ? null : activeTool);
    } else {
      const codes = Object.values(ShiftCode);
      const nextIndex = currentCode ? (codes.indexOf(currentCode) + 1) % (codes.length + 1) : 0;
      if (nextIndex < codes.length) {
        applyShift(techId, date, codes[nextIndex]);
      } else {
        applyShift(techId, date, null);
      }
    }
  };

  const handleAiSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!aiInput.trim() || isProcessingAi) return;
    setIsProcessingAi(true);
    const techNames = INITIAL_TECHNICIANS.map(t => t.name);
    const result = await parseShiftFromText(aiInput, techNames, format(currentDate, 'yyyy-MM-dd'));
    if (result) {
      const tech = INITIAL_TECHNICIANS.find(t => t.name.toLowerCase().includes(result.technicianName.toLowerCase()));
      if (tech) {
        applyShift(tech.id, result.date, result.shiftCode);
        setAiInput('');
      }
    }
    setIsProcessingAi(false);
  };

  const getShift = (techId: string, date: Date) => {
    const dateStr = format(date, 'yyyy-MM-dd');
    return shifts.find(s => s.techId === techId && s.date === dateStr);
  };

  return (
    <div className={`flex flex-col h-screen bg-slate-50 text-slate-900 font-sans overflow-hidden ${activeTool ? 'cursor-crosshair' : ''}`}>
      <div className="bg-emerald-500 text-white text-[10px] font-bold py-1 px-4 text-center tracking-widest uppercase shrink-0 relative z-50">
        Schedules are subject to change • Drag to Assign Enabled {activeTool ? `(Active: ${activeTool})` : ''}
      </div>

      <header className="bg-white border-b border-slate-200 px-6 py-4 flex items-center justify-between shrink-0 relative z-40">
        <div className="flex items-center gap-6">
          <div className="flex flex-col">
            <h1 className="text-xl font-black text-slate-800 flex items-center gap-2">
              <CalendarIcon className="w-5 h-5 text-indigo-600" />
              {format(currentDate, 'MMMM yyyy')}
            </h1>
            <span className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">Enterprise Resource Planner</span>
          </div>

          <div className="flex items-center bg-slate-100 rounded-lg p-1">
            <button onClick={() => setCurrentDate(subMonths(currentDate, 1))} className="p-1.5 hover:bg-white hover:shadow-sm rounded-md transition-all">
              <ChevronLeftIcon className="w-4 h-4" />
            </button>
            <button onClick={() => setCurrentDate(new Date())} className="px-3 py-1 text-xs font-bold hover:text-indigo-600 transition-colors text-slate-600">Today</button>
            <button onClick={() => setCurrentDate(addMonths(currentDate, 1))} className="p-1.5 hover:bg-white hover:shadow-sm rounded-md transition-all">
              <ChevronRightIcon className="w-4 h-4" />
            </button>
          </div>
        </div>

        <div className="flex items-center gap-3 flex-1 justify-center px-4">
          <form onSubmit={handleAiSubmit} className="flex-1 max-w-sm relative group">
            <SparklesIcon className={`absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 ${isProcessingAi ? 'text-indigo-500 animate-pulse' : 'text-slate-400'}`} />
