          </form>

          <div className="flex gap-2">
            <button 
              onClick={populateWrkThrough2026}
              className="px-3 py-1.5 bg-slate-800 text-white text-[10px] font-black rounded-lg hover:bg-slate-700 transition-colors shadow-sm whitespace-nowrap uppercase tracking-widest"
            >
              Fill WRK thru 2026
            </button>
            <button 
              onClick={apply2026Vacations}
              className="px-3 py-1.5 bg-indigo-600 text-white text-[10px] font-black rounded-lg hover:bg-indigo-700 transition-colors shadow-sm whitespace-nowrap uppercase tracking-widest flex items-center gap-2"
            >
              <CalendarIcon className="w-3 h-3" />
              Apply 2026 Vacations
            </button>
          </div>
        </div>

        <div className="flex gap-2 ml-4">
           {Object.entries(SHIFT_METADATA).slice(0, 4).map(([code, meta]) => (
             <button 
                key={code} 
                onClick={() => setActiveTool(activeTool === code ? null : code as ShiftCode)}
                className={`flex items-center gap-1.5 px-2 py-1 border rounded-md transition-all shadow-sm ${activeTool === code ? 'ring-2 ring-indigo-500 border-indigo-500 bg-indigo-50' : 'bg-white border-slate-200'}`}
              >
                <div className={`w-2 h-2 rounded-full ${meta.bg}`}></div>
                <span className="text-[10px] font-bold text-slate-500">{code}</span>
             </button>
           ))}
        </div>
      </header>

      <div className="flex-1 overflow-auto p-4 select-none">
        <div className="min-w-max bg-white rounded-xl shadow-xl border border-slate-200 overflow-hidden">
          <div className="flex border-b border-slate-200 sticky top-0 z-20 bg-white">
            <div className="w-64 shrink-0 bg-slate-50 border-r border-slate-200 px-4 py-3 flex items-end">
              <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Technician Information</span>
