                    <button 
                      onClick={() => fillMonthForTech(tech.id)}
                      title="Fill Month with selected Tool"
                      className="text-[8px] font-black text-indigo-500 hover:text-indigo-700 uppercase tracking-tighter bg-indigo-50 hover:bg-indigo-100 px-1 py-0.5 rounded opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap"
                    >
                      Fill Month
                    </button>
                  </div>
                </div>

                {days.map((day, idx) => {
                  const shift = getShift(tech.id, day);
                  const meta = shift ? SHIFT_METADATA[shift.code] : null;
                  const isStartOfWeek = idx % 7 === 0;
                  const dateStr = format(day, 'yyyy-MM-dd');

                  return (
                    <div
                      key={idx}
                      onMouseDown={() => {
                        handleCellAction(tech.id, dateStr, shift?.code);
                        setIsDragging(true);
                      }}
                      onMouseEnter={() => {
                        if (isDragging && activeTool) {
                          applyShift(tech.id, dateStr, activeTool);
                        }
                      }}
                      className={`w-10 h-12 shrink-0 border-r border-slate-100 flex items-center justify-center cursor-pointer transition-all
                        ${isStartOfWeek ? 'border-l-2 border-l-slate-300' : ''}
                        ${!isSameMonth(day, currentDate) ? 'bg-slate-50/20' : ''}
                        ${activeTool && !shift ? 'hover:bg-indigo-50/50' : ''}
                      `}
                    >
                      {shift ? (
                        <div className={`w-8 h-8 rounded-lg flex items-center justify-center shadow-sm text-[10px] font-black animate-in fade-in zoom-in duration-200 ${meta?.bg} ${meta?.color}`}>
                          {shift.code}
                        </div>
                      ) : (
                        <div className="w-1 h-1 rounded-full bg-slate-200 group-hover:bg-slate-300 transition-colors"></div>
                      )}
                    </div>
                  );
                })}
              </div>
            ))}
          </div>

          <div className="bg-slate-50 border-t border-slate-200">
            <div className="flex items-center h-8">
              <div className="w-64 px-4 text-[10px] font-bold text-slate-500 uppercase shrink-0 border-r border-slate-200 flex items-center">Total Scheduled</div>
              {days.map((day, idx) => {
                const count = shifts.filter(s => s.date === format(day, 'yyyy-MM-dd')).length;
                return (
                  <div key={idx} className="w-10 text-center text-[10px] font-bold text-slate-700 shrink-0">
                    {count || 0}
                  </div>
                );
              })}
            </div>
          </div>
        </div>
      </div>

      <div className="fixed bottom-6 right-6 flex flex-col items-end gap-3 pointer-events-none z-[70]">
        <div className="pointer-events-auto">
          {isLegendMinimized ? (
            <button
              onClick={() => setIsLegendMinimized(false)}
              className="bg-white p-3 rounded-full shadow-2xl border border-slate-200 hover:bg-indigo-50 transition-all flex items-center gap-2 group animate-in zoom-in duration-200"
            >
              <CalendarIcon className="w-5 h-5 text-indigo-600" />
              <span className="text-[10px] font-black text-slate-600 uppercase tracking-widest hidden group-hover:inline">Shift Legend</span>
            </button>
          ) : (
            <div className="bg-white p-4 rounded-2xl shadow-2xl border border-slate-200 animate-in slide-in-from-right duration-300 relative min-w-[320px]">
              <div className="flex justify-between items-center mb-3">
                <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Status Legend (Click to pick tool)</span>
                <button 
                  onClick={() => setIsLegendMinimized(true)}
                  className="p-1 hover:bg-slate-100 rounded-md text-slate-400 hover:text-slate-600 transition-colors"
                >
                  <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
                  </svg>
                </button>
              </div>

              <div className="grid grid-cols-4 sm:grid-cols-6 gap-2">
                {(Object.keys(SHIFT_METADATA) as Array<keyof typeof SHIFT_METADATA>).map((code) => {
                  const meta = SHIFT_METADATA[code];
                  const isActive = activeTool === code;
                  return (
                    <button
                      key={code}
                      onClick={() => setActiveTool(isActive ? null : code)}
                      title={meta.label}
                      className={`
                        flex flex-col items-center p-2 rounded-xl transition-all border
                        ${isActive ? 'ring-2 ring-indigo-500 border-indigo-500 bg-indigo-50 scale-105 z-10' : 'bg-white border-slate-100 hover:border-slate-300 hover:bg-slate-50'}
                      `}
                    >
                      <div className={`w-8 h-8 rounded-lg flex items-center justify-center text-[10px] font-black shadow-sm ${meta.bg} ${meta.color}`}>
                        {code}
                      </div>
                      <span className="text-[8px] mt-1 font-bold text-slate-500 overflow-hidden text-ellipsis whitespace-nowrap w-8 text-center">{code}</span>
                    </button>
                  );
                })}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Technician } from '../types';

interface TechManagerModalProps {
  isOpen: boolean;
  onClose: () => void;
  technicians: Technician[];
  onSave: (updatedTechs: Technician[], idMap: Record<string, string>) => void;
}

const TechManagerModal: React.FC<TechManagerModalProps> = ({ isOpen, onClose, technicians, onSave }) => {
  const [localTechs, setLocalTechs] = useState<Technician[]>(technicians);

  if (!isOpen) return null;

  const handleUpdate = (index: number, field: keyof Technician, value: string) => {
    const newTechs = [...localTechs];
    newTechs[index] = { ...newTechs[index], [field]: value };
    setLocalTechs(newTechs);
  };

  const handleAdd = () => {
    setLocalTechs([...localTechs, { id: '', name: '', code: '' }]);
  };

  const handleRemove = (index: number) => {
    if (confirm('Are you sure? All shifts for this ID will be orphaned unless you re-assign them.')) {
      setLocalTechs(localTechs.filter((_, i) => i !== index));
    }
  };

  const handleFinalSave = () => {
    // Create a mapping of old ID to new ID for shift migration
    const idMap: Record<string, string> = {};
    localTechs.forEach((newTech, index) => {
      const oldTech = technicians[index];
      if (oldTech && oldTech.id !== newTech.id && newTech.id.trim() !== '') {
        idMap[oldTech.id] = newTech.id;
      }
    });

    onSave(localTechs.filter(t => t.id.trim() !== '' && t.name.trim() !== ''), idMap);
    onClose();
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/50 p-4 backdrop-blur-sm">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-2xl overflow-hidden flex flex-col max-h-[80vh]">
        <div className="px-6 py-4 border-b border-slate-100 flex justify-between items-center bg-slate-50">
          <h3 className="text-lg font-black text-slate-800 uppercase tracking-tight">Manage Technician Team</h3>
          <button onClick={onClose} className="text-slate-400 hover:text-slate-600 transition-colors">
            <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        <div className="p-6 overflow-y-auto flex-1 space-y-3">
          <div className="grid grid-cols-12 gap-4 px-2 mb-2">
            <div className="col-span-2 text-[10px] font-black text-slate-400 uppercase">ID</div>
            <div className="col-span-7 text-[10px] font-black text-slate-400 uppercase">Full Name</div>
            <div className="col-span-2 text-[10px] font-black text-slate-400 uppercase">Code</div>
            <div className="col-span-1"></div>
          </div>
          {localTechs.map((tech, idx) => (
            <div key={idx} className="grid grid-cols-12 gap-2 items-center bg-slate-50 p-2 rounded-xl group hover:bg-slate-100 transition-colors">
              <div className="col-span-2">
                <input
                  type="text"
                  value={tech.id}
                  onChange={(e) => handleUpdate(idx, 'id', e.target.value)}
                  className="w-full bg-white border border-slate-200 rounded-lg px-2 py-1.5 text-xs font-mono focus:ring-2 focus:ring-indigo-500 outline-none"
                  placeholder="ID"
                />
              </div>
              <div className="col-span-7">
                <input
                  type="text"
                  value={tech.name}
                  onChange={(e) => handleUpdate(idx, 'name', e.target.value)}
                  className="w-full bg-white border border-slate-200 rounded-lg px-2 py-1.5 text-xs font-bold focus:ring-2 focus:ring-indigo-500 outline-none"
                  placeholder="Name"
                />
              </div>
              <div className="col-span-2">
                <input
                  type="text"
                  value={tech.code}
                  onChange={(e) => handleUpdate(idx, 'code', e.target.value)}
                  className="w-full bg-white border border-slate-200 rounded-lg px-2 py-1.5 text-xs focus:ring-2 focus:ring-indigo-500 outline-none"
                  placeholder="Code"
                />
              </div>
              <div className="col-span-1 flex justify-center">
                <button 
                  onClick={() => handleRemove(idx)}
                  className="p-1.5 text-slate-300 hover:text-rose-500 transition-colors"
                >
                  <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                  </svg>
                </button>
              </div>
            </div>
          ))}
          <button 
            onClick={handleAdd}
            className="w-full py-3 border-2 border-dashed border-slate-200 rounded-xl text-slate-400 text-xs font-bold hover:border-indigo-300 hover:text-indigo-500 transition-all flex items-center justify-center gap-2"
          >
            <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
            </svg>
            Add Technician
          </button>
        </div>

        <div className="p-6 border-t border-slate-100 flex gap-3 bg-white">
          <button
            onClick={onClose}
            className="flex-1 px-4 py-2 text-slate-600 font-bold text-xs rounded-xl hover:bg-slate-50 transition-colors uppercase tracking-widest"
          >
            Cancel
          </button>
          <button
            onClick={handleFinalSave}
            className="flex-1 px-4 py-2 bg-slate-900 text-white font-bold text-xs rounded-xl hover:bg-black transition-colors shadow-lg uppercase tracking-widest"
          >
            Save Changes
          </button>
        </div>
      </div>
    </div>
  );
};

export default TechManagerModal;

import React, { useState, useMemo, useEffect, useCallback } from 'react';
import { 
  format, 
  startOfMonth, 
  endOfMonth, 
  eachDayOfInterval, 
  isSameMonth, 
  isToday,
  addMonths,
  subMonths,
  startOfWeek,
  endOfWeek
} from 'date-fns';
import { Shift, ShiftCode, Technician } from './types';
import { ChevronLeftIcon, ChevronRightIcon, SparklesIcon, CalendarIcon } from './components/Icons';
import { parseShiftFromText } from './services/geminiService';
import TechManagerModal from './components/TechManagerModal';

const DEFAULT_TECHNICIANS: Technician[] = [
  { id: '061', name: 'Jerry Aschoff', code: '061' },
  { id: '261', name: 'Thomas Jimenez', code: '261' },
  { id: '700', name: 'Darrin Westberg', code: '700' },
  { id: '375', name: 'Bryan Baca', code: '375' },
  { id: '170', name: 'Richard Hood', code: '170' },
  { id: '171', name: 'Jason Hood', code: '171' },
  { id: '804', name: 'David Winterfeldt', code: '804' },
  { id: '435', name: 'Jeremiah Lawson', code: '435' },
  { id: '391', name: 'Mike Roth Roth', code: '391' },
  { id: '392', name: 'Anthony Paul', code: '392' },
  { id: '429', name: 'Chris Hovelsen', code: '429' },
  { id: '753', name: 'Robert Hernandez', code: '753' },
  { id: '999', name: 'Gavin Erb', code: 'GE' },
];

const SHIFT_METADATA: Record<ShiftCode, { color: string; label: string; bg: string }> = {
  [ShiftCode.OOL]: { color: 'text-white', bg: 'bg-blue-900', label: 'Out of Line' },
  [ShiftCode.BLK]: { color: 'text-slate-500', bg: 'bg-slate-200', label: 'Blackout' },
  [ShiftCode.AIR]: { color: 'text-amber-700', bg: 'bg-amber-100', label: 'Air' },
  [ShiftCode.C]: { color: 'text-emerald-700', bg: 'bg-emerald-100', label: 'C-Shift' },
  [ShiftCode.WRK]: { color: 'text-slate-700', bg: 'bg-slate-100', label: 'Work' },
  [ShiftCode.E]: { color: 'text-slate-700', bg: 'bg-slate-100', label: 'Office' },
  [ShiftCode.NS]: { color: 'text-white', bg: 'bg-rose-600', label: 'No Show' },
  [ShiftCode.V]: { color: 'text-white', bg: 'bg-indigo-600', label: 'Vacation' },
  [ShiftCode.U24]: { color: 'text-blue-600', bg: 'bg-blue-50', label: '24 Unit' },
  [ShiftCode.PDP]: { color: 'text-white', bg: 'bg-purple-600', label: 'PDP Day' },
  [ShiftCode.ENT]: { color: 'text-white', bg: 'bg-teal-600', label: 'Entitlement' },
};

const App: React.FC = () => {
  const [currentDate, setCurrentDate] = useState(new Date()); 
  const [technicians, setTechnicians] = useState<Technician[]>(() => {
    const saved = localStorage.getItem('tech_list');
    return saved ? JSON.parse(saved) : DEFAULT_TECHNICIANS;
  });
  const [shifts, setShifts] = useState<Shift[]>(() => {
    const saved = localStorage.getItem('tech_shifts');
    return saved ? JSON.parse(saved) : [];
  });
  const [aiInput, setAiInput] = useState('');
  const [isProcessingAi, setIsProcessingAi] = useState(false);

  const [activeTool, setActiveTool] = useState<ShiftCode | null>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [isLegendMinimized, setIsLegendMinimized] = useState(false);
  const [isTechModalOpen, setIsTechModalOpen] = useState(false);

  useEffect(() => {
    localStorage.setItem('tech_shifts', JSON.stringify(shifts));
  }, [shifts]);

  useEffect(() => {
    localStorage.setItem('tech_list', JSON.stringify(technicians));
  }, [technicians]);

  useEffect(() => {
    const handleMouseUp = () => setIsDragging(false);
    window.addEventListener('mouseup', handleMouseUp);
    return () => window.removeEventListener('mouseup', handleMouseUp);
  }, []);

  const days = useMemo(() => {
    const start = startOfWeek(startOfMonth(currentDate));
    const end = endOfWeek(endOfMonth(currentDate));
    return eachDayOfInterval({ start, end });
  }, [currentDate]);

  const applyShift = useCallback((techId: string, date: string, code: ShiftCode | null) => {
    setShifts(prev => {
      const filtered = prev.filter(s => !(s.techId === techId && s.date === date));
      if (code) {
        return [...filtered, { techId, date, code }];
      }
      return filtered;
    });
  }, []);

  const handleTechSave = (updatedTechs: Technician[], idMap: Record<string, string>) => {
    setTechnicians(updatedTechs);

    // If IDs changed, migrate shifts to the new IDs
    if (Object.keys(idMap).length > 0) {
      setShifts(prev => prev.map(shift => ({
        ...shift,
        techId: idMap[shift.techId] || shift.techId
      })));
    }
  };

  const apply2026Vacations = () => {
    const confirmV = window.confirm("This will overwrite existing shifts on specific vacation dates in 2026. Proceed?");
    if (!confirmV) return;

    const range = (start: string, end: string) => {
      return eachDayOfInterval({ start: new Date(start), end: new Date(end) }).map(d => format(d, 'yyyy-MM-dd'));
    };

    const vacationData: Record<string, string[]> = {
      '700': ['2026-01-02', '2026-04-23', '2026-04-24', ...range('2026-07-06', '2026-07-10'), ...range('2026-11-23', '2026-11-27'), ...range('2026-12-07', '2026-12-11'), ...range('2026-12-14', '2026-12-18'), ...range('2026-12-28', '2026-12-31')],
      '392': ['2026-01-02', ...range('2026-03-23', '2026-03-27'), ...range('2026-06-01', '2026-06-05'), ...range('2026-12-28', '2026-12-31')],
      '804': ['2026-01-02', '2026-01-23', '2026-01-30', '2026-02-13', '2026-02-20', '2026-03-13', ...range('2026-03-16', '2026-03-20'), '2026-04-10', '2026-04-17', '2026-04-24', '2026-07-31', '2026-09-18', ...range('2026-09-21', '2026-09-30'), '2026-10-01', '2026-10-02', ...range('2026-12-21', '2026-12-24')],
      '170': ['2026-01-05', ...range('2026-01-20', '2026-01-23'), ...range('2026-03-23', '2026-03-27')],
      '375': [...range('2026-01-05', '2026-01-09'), ...range('2026-01-12', '2026-01-16'), ...range('2026-05-18', '2026-05-22')],
      '261': ['2026-01-16', '2026-03-16', '2026-04-17', '2026-04-20', '2026-05-22', ...range('2026-05-26', '2026-05-29'), ...range('2026-06-22', '2026-06-23'), ...range('2026-07-06', '2026-07-10'), ...range('2026-09-04', '2026-09-11'), ...range('2026-11-23', '2026-11-27')],
      '171': [...range('2026-01-26', '2026-01-27'), '2026-03-20', '2026-03-30', '2026-04-10', '2026-04-14', '2026-05-14', '2026-05-15', '2026-05-18'],
      '391': [...range('2026-02-02', '2026-02-06'), ...range('2026-02-09', '2026-02-13'), ...range('2026-06-22', '2026-06-23'), ...range('2026-06-24', '2026-06-26'), ...range('2026-06-29', '2026-07-03')],
      '753': [...range('2026-02-16', '2026-02-20')],
      '061': [ ...range('2026-05-26', '2026-05-29'), '2026-06-05', ...range('2026-06-08', '2026-06-12'), '2026-07-03', '2026-07-17', ...range('2026-07-20', '2026-07-24'), '2026-08-07', '2026-08-14', '2026-09-04', ...range('2026-09-08', '2026-09-11')],
      '429': [...range('2026-06-15', '2026-06-19'), ...range('2026-07-20', '2026-07-24'), ...range('2026-11-02', '2026-11-06')],
      '435': [...range('2026-07-13', '2026-07-17'), ...range('2026-07-27', '2026-07-31'), ...range('2026-12-21', '2026-12-24')]
    };

    setShifts(prev => {
      let nextShifts = [...prev];
      Object.entries(vacationData).forEach(([techId, dates]) => {
        dates.forEach(date => {
          nextShifts = nextShifts.filter(s => !(s.techId === techId && s.date === date));
          nextShifts.push({ techId, date, code: ShiftCode.V });
        });
      });
      return nextShifts;
    });
    alert("2026 Vacations applied successfully!");
  };

  const fillMonthForTech = (techId: string) => {
    if (!activeTool) {
      alert("Please select a status from the legend first to use as a fill tool.");
      return;
    }
    const start = startOfMonth(currentDate);
    const end = endOfMonth(currentDate);
    const monthDays = eachDayOfInterval({ start, end });
    setShifts(prev => {
      const otherShifts = prev.filter(s => {
        const isThisTech = s.techId === techId;
        const isThisMonth = isSameMonth(new Date(s.date), currentDate);
        return !(isThisTech && isThisMonth);
      });
      const newMonthShifts = monthDays.map(day => ({
        techId,
        date: format(day, 'yyyy-MM-dd'),
        code: activeTool
      }));
      return [...otherShifts, ...newMonthShifts];
    });
  };

  const populateWrkThrough2026 = () => {
    const confirmPopulate = window.confirm("This will fill all empty dates from today through December 31, 2026 with the 'WRK' status for all technicians. Proceed?");
    if (!confirmPopulate) return;
    const startDate = new Date();
    const endDate = new Date(2026, 11, 31);
    const allDays = eachDayOfInterval({ start: startDate, end: endDate });
    setShifts(prev => {
      const shiftMap = new Map();
      prev.forEach(s => shiftMap.set(`${s.techId}_${s.date}`, s));
      const newShifts = [...prev];
      technicians.forEach(tech => {
        allDays.forEach(day => {
          const dateStr = format(day, 'yyyy-MM-dd');
          const key = `${tech.id}_${dateStr}`;
          if (!shiftMap.has(key)) {
            newShifts.push({ techId: tech.id, date: dateStr, code: ShiftCode.WRK });
          }
        });
      });
      return newShifts;
    });
    alert("Schedule populated with WRK status through 2026!");
  };

  const handleCellAction = (techId: string, date: string, currentCode?: ShiftCode) => {
    if (activeTool) {
      applyShift(techId, date, activeTool === currentCode ? null : activeTool);
    } else {
      const codes = Object.values(ShiftCode);
      const nextIndex = currentCode ? (codes.indexOf(currentCode) + 1) % (codes.length + 1) : 0;
      if (nextIndex < codes.length) {
        applyShift(techId, date, codes[nextIndex]);
      } else {
        applyShift(techId, date, null);
      }
    }
  };

  const handleAiSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!aiInput.trim() || isProcessingAi) return;
    setIsProcessingAi(true);
    const techNames = technicians.map(t => t.name);
    const result = await parseShiftFromText(aiInput, techNames, format(currentDate, 'yyyy-MM-dd'));
    if (result) {
      const tech = technicians.find(t => t.name.toLowerCase().includes(result.technicianName.toLowerCase()));
      if (tech) {
        applyShift(tech.id, result.date, result.shiftCode);
        setAiInput('');
      }
    }
    setIsProcessingAi(false);
  };

  const getShift = (techId: string, date: Date) => {
    const dateStr = format(date, 'yyyy-MM-dd');
    return shifts.find(s => s.techId === techId && s.date === dateStr);
  };

  return (
    <div className={`flex flex-col h-screen bg-slate-50 text-slate-900 font-sans overflow-hidden ${activeTool ? 'cursor-crosshair' : ''}`}>
      <TechManagerModal 
        isOpen={isTechModalOpen} 
        onClose={() => setIsTechModalOpen(false)} 
        technicians={technicians}
        onSave={handleTechSave}
      />

      <div className="bg-emerald-500 text-white text-[10px] font-bold py-1 px-4 text-center tracking-widest uppercase shrink-0 relative z-50">
        Schedules are subject to change • Drag to Assign Enabled {activeTool ? `(Active: ${activeTool})` : ''}
      </div>

      <header className="bg-white border-b border-slate-200 px-6 py-4 flex items-center justify-between shrink-0 relative z-40">
        <div className="flex items-center gap-6">
          <div className="flex flex-col">
            <h1 className="text-xl font-black text-slate-800 flex items-center gap-2">
              <CalendarIcon className="w-5 h-5 text-indigo-600" />
              {format(currentDate, 'MMMM yyyy')}
            </h1>
            <span className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">Enterprise Resource Planner</span>
          </div>

          <div className="flex items-center bg-slate-100 rounded-lg p-1">
            <button onClick={() => setCurrentDate(subMonths(currentDate, 1))} className="p-1.5 hover:bg-white hover:shadow-sm rounded-md transition-all">
              <ChevronLeftIcon className="w-4 h-4" />
            </button>
            <button onClick={() => setCurrentDate(new Date())} className="px-3 py-1 text-xs font-bold hover:text-indigo-600 transition-colors text-slate-600">Today</button>
            <button onClick={() => setCurrentDate(addMonths(currentDate, 1))} className="p-1.5 hover:bg-white hover:shadow-sm rounded-md transition-all">
              <ChevronRightIcon className="w-4 h-4" />
            </button>
          </div>
        </div>

        <div className="flex items-center gap-3 flex-1 justify-center px-4">
          <form onSubmit={handleAiSubmit} className="flex-1 max-w-sm relative group">
            <SparklesIcon className={`absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 ${isProcessingAi ? 'text-indigo-500 animate-pulse' : 'text-slate-400'}`} />
            <input 
              type="text"
              placeholder="AI Assign..."
              className="w-full bg-slate-100 border-none rounded-xl pl-10 pr-4 py-2 text-sm focus:ring-2 focus:ring-indigo-500 transition-all outline-none"
              value={aiInput}
              onChange={(e) => setAiInput(e.target.value)}
            />
          </form>

          <div className="flex gap-2">
            <button 
              onClick={() => setIsTechModalOpen(true)}
              className="px-3 py-1.5 bg-slate-100 text-slate-800 text-[10px] font-black rounded-lg hover:bg-slate-200 transition-colors shadow-sm whitespace-nowrap uppercase tracking-widest border border-slate-200"
            >
              Manage Team
            </button>
            <button 
              onClick={populateWrkThrough2026}
              className="px-3 py-1.5 bg-slate-800 text-white text-[10px] font-black rounded-lg hover:bg-slate-700 transition-colors shadow-sm whitespace-nowrap uppercase tracking-widest"
            >
              Fill WRK thru 2026
            </button>
            <button 
              onClick={apply2026Vacations}
              className="px-3 py-1.5 bg-indigo-600 text-white text-[10px] font-black rounded-lg hover:bg-indigo-700 transition-colors shadow-sm whitespace-nowrap uppercase tracking-widest flex items-center gap-2"
            >
              <CalendarIcon className="w-3 h-3" />
              Apply 2026 Vacations
            </button>
          </div>
        </div>

        <div className="flex gap-2 ml-4">
           {Object.entries(SHIFT_METADATA).slice(0, 4).map(([code, meta]) => (
             <button 
                key={code} 
                onClick={() => setActiveTool(activeTool === code ? null : code as ShiftCode)}
                className={`flex items-center gap-1.5 px-2 py-1 border rounded-md transition-all shadow-sm ${activeTool === code ? 'ring-2 ring-indigo-500 border-indigo-500 bg-indigo-50' : 'bg-white border-slate-200'}`}
              >
                <div className={`w-2 h-2 rounded-full ${meta.bg}`}></div>
                <span className="text-[10px] font-bold text-slate-500">{code}</span>
             </button>
           ))}
        </div>
      </header>

      <div className="flex-1 overflow-auto p-4 select-none">
        <div className="min-w-max bg-white rounded-xl shadow-xl border border-slate-200 overflow-hidden">
          <div className="flex border-b border-slate-200 sticky top-0 z-20 bg-white">
            <div className="w-64 shrink-0 bg-slate-50 border-r border-slate-200 px-4 py-3 flex items-end">
              <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Technician Information</span>
            </div>
            {days.map((day, idx) => {
              const isStartOfWeek = idx % 7 === 0;
              return (
                <div 
                  key={idx} 
                  className={`w-10 shrink-0 flex flex-col items-center py-2 border-r border-slate-100 
                    ${isStartOfWeek ? 'border-l-2 border-l-slate-300 bg-slate-50/50' : ''}
                    ${!isSameMonth(day, currentDate) ? 'opacity-30' : ''}
                    ${isToday(day) ? 'bg-indigo-50' : ''}
                  `}
                >
                  <span className="text-[9px] font-bold text-slate-400 uppercase">{format(day, 'eeeee')}</span>
                  <span className={`text-xs font-black mt-0.5 ${isToday(day) ? 'text-indigo-600' : 'text-slate-700'}`}>{format(day, 'd')}</span>
                </div>
              );
            })}
          </div>

          <div className="divide-y divide-slate-100">
            {technicians.map((tech) => (
              <div key={tech.id} className="flex hover:bg-slate-50 transition-colors group">
                <div className="w-64 shrink-0 px-4 py-2 border-r border-slate-200 flex items-center justify-between sticky left-0 z-10 bg-inherit shadow-[4px_0_10px_-5px_rgba(0,0,0,0.05)]">
                  <div className="flex flex-col">
                    <span className="text-sm font-bold text-slate-800">{tech.name}</span>
                    <span className="text-[10px] text-slate-400 font-mono tracking-tighter">ID: {tech.id}</span>
                  </div>
                  <div className="flex flex-col items-end gap-1">
                    <span className="text-[10px] font-black text-slate-300 bg-slate-100 px-1.5 py-0.5 rounded uppercase">{tech.code}</span>
                    <button 
                      onClick={() => fillMonthForTech(tech.id)}
                      title="Fill Month with selected Tool"
                      className="text-[8px] font-black text-indigo-500 hover:text-indigo-700 uppercase tracking-tighter bg-indigo-50 hover:bg-indigo-100 px-1 py-0.5 rounded opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap"
                    >
                      Fill Month
                    </button>
                  </div>
                </div>

                {days.map((day, idx) => {
                  const shift = getShift(tech.id, day);
                  const meta = shift ? SHIFT_METADATA[shift.code] : null;
                  const isStartOfWeek = idx % 7 === 0;
                  const dateStr = format(day, 'yyyy-MM-dd');

                  return (
                    <div
                      key={idx}
                      onMouseDown={() => {
                        handleCellAction(tech.id, dateStr, shift?.code);
                        setIsDragging(true);
                      }}
                      onMouseEnter={() => {
                        if (isDragging && activeTool) {
                          applyShift(tech.id, dateStr, activeTool);
                        }
                      }}
                      className={`w-10 h-12 shrink-0 border-r border-slate-100 flex items-center justify-center cursor-pointer transition-all
                        ${isStartOfWeek ? 'border-l-2 border-l-slate-300' : ''}
                        ${!isSameMonth(day, currentDate) ? 'bg-slate-50/20' : ''}
                        ${activeTool && !shift ? 'hover:bg-indigo-50/50' : ''}
                      `}
                    >
                      {shift ? (
                        <div className={`w-8 h-8 rounded-lg flex items-center justify-center shadow-sm text-[10px] font-black animate-in fade-in zoom-in duration-200 ${meta?.bg} ${meta?.color}`}>
                          {shift.code}
                        </div>
                      ) : (
                        <div className="w-1 h-1 rounded-full bg-slate-200 group-hover:bg-slate-300 transition-colors"></div>
                      )}
                    </div>
                  );
                })}
              </div>
            ))}
          </div>

          <div className="bg-slate-50 border-t border-slate-200">
            <div className="flex items-center h-8">
              <div className="w-64 px-4 text-[10px] font-bold text-slate-500 uppercase shrink-0 border-r border-slate-200 flex items-center">Total Scheduled</div>
              {days.map((day, idx) => {
                const count = shifts.filter(s => s.date === format(day, 'yyyy-MM-dd')).length;
                return (
                  <div key={idx} className="w-10 text-center text-[10px] font-bold text-slate-700 shrink-0">
                    {count || 0}
                  </div>
                );
              })}
            </div>
          </div>
        </div>
      </div>

      <div className="fixed bottom-6 right-6 flex flex-col items-end gap-3 pointer-events-none z-[70]">
        <div className="pointer-events-auto">
          {isLegendMinimized ? (
            <button
              onClick={() => setIsLegendMinimized(false)}
              className="bg-white p-3 rounded-full shadow-2xl border border-slate-200 hover:bg-indigo-50 transition-all flex items-center gap-2 group animate-in zoom-in duration-200"
            >
              <CalendarIcon className="w-5 h-5 text-indigo-600" />
              <span className="text-[10px] font-black text-slate-600 uppercase tracking-widest hidden group-hover:inline">Shift Legend</span>
            </button>
          ) : (
            <div className="bg-white p-4 rounded-2xl shadow-2xl border border-slate-200 animate-in slide-in-from-right duration-300 relative min-w-[320px]">
              <div className="flex justify-between items-center mb-3">
                <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Status Legend (Click to pick tool)</span>
                <button 
                  onClick={() => setIsLegendMinimized(true)}
                  className="p-1 hover:bg-slate-100 rounded-md text-slate-400 hover:text-slate-600 transition-colors"
                >
                  <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
                  </svg>
                </button>
              </div>

              <div className="grid grid-cols-4 sm:grid-cols-6 gap-2">
                {(Object.keys(SHIFT_METADATA) as Array<keyof typeof SHIFT_METADATA>).map((code) => {
                  const meta = SHIFT_METADATA[code];
                  const isActive = activeTool === code;
                  return (
                    <button
                      key={code}
                      onClick={() => setActiveTool(isActive ? null : code)}
                      title={meta.label}
                      className={`
                        flex flex-col items-center p-2 rounded-xl transition-all border
                        ${isActive ? 'ring-2 ring-indigo-500 border-indigo-500 bg-indigo-50 scale-105 z-10' : 'bg-white border-slate-100 hover:border-slate-300 hover:bg-slate-50'}
                      `}
                    >
                      <div className={`w-8 h-8 rounded-lg flex items-center justify-center text-[10px] font-black shadow-sm ${meta.bg} ${meta.color}`}>
                        {code}
                      </div>
                      <span className="text-[8px] mt-1 font-bold text-slate-500 overflow-hidden text-ellipsis whitespace-nowrap w-8 text-center">{code}</span>
                    </button>
                  );
                })}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default App;
